-- Replace placeholder director signature in contract template v1.0
-- with the image at web/src/content/legal/director-signature.jpg.

UPDATE contract_templates
SET html_content = regexp_replace(
  html_content,
  'src="data:image/jpeg;base64,[^"]+"'::text,
  ('src="data:image/jpeg;base64,"'::text)
)
WHERE version = 'v1.0'
  AND html_content ~ 'src="data:image/jpeg;base64,';
